import 'package:flutter/material.dart'; import '../theme/app_theme.dart'; class AppIconButton extends StatelessWidget { final IconData icon; final VoidCallback? onPressed; final Color? color; final double size; const AppIconButton({super.key, required this.icon, this.onPressed, this.color, this.size = 42}); @override Widget build(BuildContext context) => Material(color: AppTheme.darkCard, borderRadius: BorderRadius.circular(12), child: InkWell(onTap: onPressed, borderRadius: BorderRadius.circular(12), child: Container(width: size, height: size, child: Icon(icon, color: color ?? AppTheme.darkText, size: 20)))); }
